INSERT INTO `cms_blogs` (`id`, `slug`, `title`, `excerpt`, `content`, `cover_image`, `author_id`, `is_published`, `published_at`, `created_at`, `updated_at`) VALUES (7,'summer-fitness-2026','Summer Fitness Guide 2026','Stay active this summer with our complete fitness guide for tennis, padel, and more.','<p>Summer is here and it is the perfect time to get active! Whether you are a seasoned athlete or just starting, our guide covers everything you need about staying fit through sports this summer.</p><h3>Pick Your Sport</h3><p>Tennis and padel are fantastic full-body workouts that improve cardiovascular health, coordination, and mental focus.</p><h3>Stay Hydrated</h3><p>Always bring water to your sessions. For intense matches, consider sports drinks to replenish electrolytes.</p><h3>Book Smart</h3><p>Use CourtZon to book courts during cooler morning or evening hours. Our real-time availability makes it easy.</p>','',1,1,'2026-05-21 11:47:45','2026-05-21 11:47:45','2026-05-21 11:47:45'),(8,'benefits-of-playing-padel','Why Padel is the Fastest Growing Sport','Discover why padel tennis is taking the world by storm and how you can get started.','<p>Padel tennis has exploded in popularity across the Middle East, Europe, and beyond. But what makes this racket sport so addictive?</p><h3>Easy to Learn</h3><p>Unlike tennis, padel has a shorter learning curve. The enclosed court and underhand serve make it accessible to all ages and skill levels.</p><h3>Social Sport</h3><p>Padel is always played in doubles, making it a highly social activity. Perfect for spending time with friends while getting a great workout.</p><h3>Fast-Paced Action</h3><p>The smaller court and wall bounces create exciting, fast-paced rallies that keep every player engaged.</p><p>Ready to try? Browse padel courts near you on CourtZon and book your first game today!</p>','',1,1,'2026-05-21 11:47:45','2026-05-21 11:47:45','2026-05-21 11:47:45'),(9,'tournament-guide-for-beginners','Your First Tournament: A Beginner Guide','Everything you need to know before signing up for your first sports tournament.','<p>Signing up for your first tournament can be intimidating. This guide will help you prepare and make the most of your competitive debut.</p><h3>Choose the Right Level</h3><p>Be honest about your skill level. Tournaments are divided into categories for a reason. Starting at the right level ensures competitive, enjoyable matches.</p><h3>Prepare Your Gear</h3><p>Bring extra equipment: spare rackets, grip tape, water, snacks, and a towel. Check the tournament rules for specific requirements.</p><h3>Arrive Early</h3><p>Give yourself at least 30 minutes to warm up, check in, and get familiar with the venue.</p><h3>Enjoy the Experience</h3><p>Win or lose, tournaments are about the experience. Meet new players, learn from your matches, and have fun!</p>','',1,1,'2026-05-21 11:47:45','2026-05-21 11:47:45','2026-05-21 11:47:45');
