INSERT INTO `cms_section_blocks` (`id`, `page_id`, `block_type`, `block_key`, `title`, `subtitle`, `content`, `style_config`, `sort_order`, `is_active`, `created_at`, `updated_at`) VALUES (3,6,'hero','hero_blog','Blog','Insights, tips, and stories from the CourtZon community.','{\"heading\": \"Blog\", \"subheading\": \"Insights, tips, and stories from the CourtZon community.\", \"ctaText\": \"\", \"ctaLink\": \"\"}',NULL,0,1,'2026-06-13 16:19:29','2026-06-13 16:19:29'),(4,6,'blog_preview','blog_preview_main','Latest Posts','','{}',NULL,1,1,'2026-06-13 16:19:29','2026-06-13 16:19:29'),(26,16,'hero','hero_main','Transform Your Court Experience','The all-in-one platform for players and organizations','{\"heading\":\"Transform Your Court Experience\",\"subheading\":\"Book courts, join tournaments, build your sports community — all in one place. CourtZon empowers players to find and book the perfect court, and gives organizations the tools to manage facilities, grow revenue, and engage their community.\",\"ctaText\":\"Get Started Free\",\"ctaLink\":\"/register\",\"secondaryCtaText\":\"Learn More\",\"secondaryCtaLink\":\"#features\",\"backgroundImage\":\"\"}',NULL,0,1,'2026-05-21 11:47:45','2026-05-21 11:47:45'),(27,16,'features','feat_players','For Players','Everything you need to play your favorite sports','{\"columns\":3,\"features\":[{\"icon\":\"booking\",\"title\":\"Easy Court Booking\",\"description\":\"Find and book tennis, padel, football, basketball courts near you. Real-time availability and instant confirmation.\"},{\"icon\":\"compete\",\"title\":\"Tournaments & Leagues\",\"description\":\"Join competitive and social tournaments. Create brackets, track scores, and compete with players at your level.\"},{\"icon\":\"coach\",\"title\":\"Find Coaches & Academies\",\"description\":\"Connect with qualified coaches for private sessions or enroll in academies to improve your game.\"},{\"icon\":\"community\",\"title\":\"Build Your Community\",\"description\":\"Make friends, join groups, attend events. CourtZon is more than booking — it is your sports social network.\"},{\"icon\":\"marketplace\",\"title\":\"Sports Marketplace\",\"description\":\"Buy and sell sports equipment, gear, and accessories from trusted sellers.\"},{\"icon\":\"star\",\"title\":\"Track Your Progress\",\"description\":\"Monitor your match history, rankings, and statistics. Level up your game with insights.\"}]}',NULL,1,1,'2026-05-21 11:47:45','2026-05-21 11:47:45'),(28,16,'features','feat_orgs','For Organizations','Powerful tools to manage and grow your facility','{\"columns\":3,\"features\":[{\"icon\":\"calendar\",\"title\":\"Schedule Management\",\"description\":\"Manage all your courts and resources with an intuitive calendar. Set pricing, availability, and booking rules.\"},{\"icon\":\"chart\",\"title\":\"Revenue & Analytics\",\"description\":\"Track revenue, bookings, and utilization. Get real-time reports and business insights.\"},{\"icon\":\"shield\",\"title\":\"Access Control\",\"description\":\"Control who accesses your facilities. Manage memberships, guest passes, and branch-level permissions.\"},{\"icon\":\"bolt\",\"title\":\"Sell Memberships\",\"description\":\"Create subscription plans with recurring billing. Offer monthly, quarterly, or annual memberships.\"},{\"icon\":\"community\",\"title\":\"Engage Your Players\",\"description\":\"Run tournaments, post events, send notifications. Build a loyal community around your facility.\"},{\"icon\":\"star\",\"title\":\"Multi-Branch Ready\",\"description\":\"Manage multiple branches under one organization with independent pricing and staff.\"}]}',NULL,2,1,'2026-05-21 11:47:45','2026-05-21 11:47:45'),(29,16,'stats','stats_home','Trusted across the region',NULL,'{\"stats\":[{\"label\":\"Courts Listed\",\"value\":\"500+\"},{\"label\":\"Active Players\",\"value\":\"10,000+\"},{\"label\":\"Organizations\",\"value\":\"150+\"},{\"label\":\"Tournaments\",\"value\":\"1,200+\"}]}',NULL,3,1,'2026-05-21 11:47:45','2026-05-21 11:47:45'),(30,16,'testimonials','test_home','What Our Users Say',NULL,'{\"testimonials\":[{\"name\":\"Ahmed K.\",\"role\":\"Tennis Player\",\"quote\":\"CourtZon made it so easy to find courts near me. I book in seconds and never miss a game.\"},{\"name\":\"Sarah M.\",\"role\":\"Club Owner\",\"quote\":\"Since switching to CourtZon, our court utilization went up 40%. The analytics helped us grow faster.\"},{\"name\":\"Omar R.\",\"role\":\"Padel Enthusiast\",\"quote\":\"I love the community features. Met so many great players through CourtZon events.\"}]}',NULL,4,1,'2026-05-21 11:47:45','2026-05-21 11:47:45'),(32,16,'cta','cta_home','Ready to transform your court experience?','Join thousands of players and organizations already on CourtZon.','{\"buttonText\":\"Sign Up Free\",\"buttonLink\":\"/register\"}',NULL,6,1,'2026-05-21 11:47:45','2026-05-21 11:47:45'),(33,17,'hero','about_hero','About CourtZon','Revolutionizing sports court management','{\"heading\":\"About CourtZon\",\"subheading\":\"We are on a mission to make sports accessible, organized, and enjoyable for everyone.\"}',NULL,0,1,'2026-05-21 11:47:45','2026-05-21 11:47:45'),(34,17,'text','about_text','Our Story',NULL,'{\"html\":\"<p>CourtZon was founded with a simple idea: booking a sports court should be as easy as booking a hotel room. We saw players struggling to find available courts, organizations losing revenue to inefficient scheduling, and a fragmented sports community with no central hub.</p><p>Today, CourtZon serves thousands of players and hundreds of organizations. Our platform handles everything from real-time booking and payments to tournament management and community engagement.</p><p>We believe that sports bring people together. Our mission is to remove every barrier between a player and their next game.</p>\"}',NULL,1,1,'2026-05-21 11:47:45','2026-05-21 11:47:45'),(35,17,'stats','about_stats','CourtZon by the Numbers',NULL,'{\"stats\":[{\"label\":\"Years Active\",\"value\":\"3+\"},{\"label\":\"Cities\",\"value\":\"25+\"},{\"label\":\"Team Members\",\"value\":\"30+\"},{\"label\":\"Happy Users\",\"value\":\"15k+\"}]}',NULL,2,1,'2026-05-21 11:47:45','2026-05-21 11:47:45'),(36,18,'hero','miss_hero','Mission & Vision','What drives us forward every day','{\"heading\":\"Our Mission & Vision\",\"subheading\":\"Building the future of sports, one court at a time.\"}',NULL,0,1,'2026-05-21 11:47:45','2026-05-21 11:47:45'),(37,18,'text','miss_text','Our Mission','To make every court accessible, every game bookable, and every player connected.','{\"html\":\"<p>CourtZon exists to democratize access to sports facilities. We believe that finding and booking a court should be instant, transparent, and frictionless.</p><h3>Our Vision</h3><p>We envision a world where every sports facility is digitized, every court is discoverable, and every player can find the perfect place to play.</p><h3>Our Values</h3><div class=\\\"grid grid-cols-1 md:grid-cols-2 gap-6\\\"><div class=\\\"bg-gray-50 p-6 rounded-xl\\\"><h4 class=\\\"font-bold text-lg mb-2\\\">Player First</h4><p>Every decision starts with the player experience.</p></div><div class=\\\"bg-gray-50 p-6 rounded-xl\\\"><h4 class=\\\"font-bold text-lg mb-2\\\">Partner Success</h4><p>When our partners grow, we grow.</p></div><div class=\\\"bg-gray-50 p-6 rounded-xl\\\"><h4 class=\\\"font-bold text-lg mb-2\\\">Relentless Innovation</h4><p>We never settle. We constantly push boundaries.</p></div><div class=\\\"bg-gray-50 p-6 rounded-xl\\\"><h4 class=\\\"font-bold text-lg mb-2\\\">Integrity Always</h4><p>Transparency and honesty in every interaction.</p></div></div>\"}',NULL,1,1,'2026-05-21 11:47:45','2026-05-21 11:47:45'),(38,19,'hero','team_hero','Meet Our Team','The passionate people behind CourtZon','{\"heading\":\"Our Team\",\"subheading\":\"A diverse team united by a love for sports and technology.\"}',NULL,0,1,'2026-05-21 11:47:45','2026-05-21 11:47:45'),(39,19,'team','team_grid','Leadership',NULL,'{\"columns\":3,\"members\":[{\"name\":\"Mohamed Niazy\",\"role\":\"Founder & CEO\",\"bio\":\"Visionary leader with 15+ years in sports tech.\"},{\"name\":\"Ahmed Hassan\",\"role\":\"CTO\",\"bio\":\"Full-stack architect passionate about scalable systems.\"},{\"name\":\"Layla Ibrahim\",\"role\":\"Head of Product\",\"bio\":\"UX specialist creating intuitive sports experiences.\"},{\"name\":\"Karim Adel\",\"role\":\"Head of Operations\",\"bio\":\"Operations expert ensuring smooth facility onboarding.\"},{\"name\":\"Nour El-Din\",\"role\":\"Head of Marketing\",\"bio\":\"Growth strategist connecting players with the platform.\"},{\"name\":\"Mona Salah\",\"role\":\"Head of Partnerships\",\"bio\":\"Building relationships with sports organizations.\"}]}',NULL,1,1,'2026-05-21 11:47:45','2026-05-21 11:47:45'),(40,20,'hero','cont_hero','Contact Us','We would love to hear from you','{\"heading\":\"Get in Touch\",\"subheading\":\"Have questions, feedback, or want to partner with us? Reach out!\"}',NULL,0,1,'2026-05-21 11:47:45','2026-05-21 11:47:45'),(41,20,'contact_form','cont_form','Send Us a Message','Fill out the form and we will get back to you within 24 hours.','{}',NULL,1,1,'2026-05-21 11:47:45','2026-05-21 11:47:45'),(42,21,'hero','faq_hero','Frequently Asked Questions','Quick answers to common questions','{\"heading\":\"FAQ\",\"subheading\":\"Find answers to the most common questions about CourtZon.\"}',NULL,0,1,'2026-05-21 11:47:45','2026-05-21 11:47:45'),(43,21,'faq','faq_items','Common Questions',NULL,'{\"items\":[{\"question\":\"How do I book a court?\",\"answer\":\"Simply browse courts near you, select your preferred sport and time slot, and confirm your booking. You can pay securely online and receive instant confirmation.\"},{\"question\":\"Is CourtZon free for players?\",\"answer\":\"Yes! Creating an account and browsing courts is completely free. You only pay for the court bookings you make at rates set by the facility.\"},{\"question\":\"How do I join a tournament?\",\"answer\":\"Visit the Tournaments section, browse upcoming events, and click Join on any tournament that matches your skill level.\"},{\"question\":\"Can I cancel a booking?\",\"answer\":\"Yes, you can cancel a booking up to the cancellation deadline set by the facility. Check the booking details for the specific policy.\"},{\"question\":\"How do I list my facility on CourtZon?\",\"answer\":\"Visit our Sell With Us page or contact our partnerships team. We will guide you through the onboarding process.\"},{\"question\":\"What sports are supported?\",\"answer\":\"Tennis, padel, football, basketball, volleyball, squash, badminton, and many more. If your sport needs a court, we support it.\"},{\"question\":\"Is my payment secure?\",\"answer\":\"Absolutely. We use industry-standard encryption and never store your full credit card details. All payments are PCI-compliant.\"},{\"question\":\"How do I become a coach?\",\"answer\":\"Create your profile, add your qualifications, set your availability and rates. Players will be able to find and book sessions with you.\"},{\"question\":\"Can I sell products on CourtZon?\",\"answer\":\"Yes! Visit the Sell With Us section to learn about becoming a seller. List sports equipment, gear, and accessories.\"},{\"question\":\"How do I contact support?\",\"answer\":\"You can reach us through the Contact page, email support@courtzon.com, or use the live chat when logged in.\"}]}',NULL,1,1,'2026-05-21 11:47:45','2026-05-21 11:47:45'),(44,22,'hero','priv_hero','Privacy Policy',NULL,'{\"heading\":\"Privacy Policy\",\"subheading\":\"Last updated: January 2026\"}',NULL,0,1,'2026-05-21 11:47:45','2026-05-21 11:47:45'),(45,22,'text','priv_text',NULL,NULL,'{\"html\":\"<h3>1. Information We Collect</h3><p>We collect information you provide directly, such as your name, email, phone number, and payment information when you create an account or make a booking. We also collect technical information including device info and usage data.</p><h3>2. How We Use Your Information</h3><p>We use your information to provide and improve our services, process transactions, send notifications, and comply with legal obligations.</p><h3>3. Information Sharing</h3><p>We share your information with facility owners when you book, with payment processors to complete transactions, and as required by law. We do not sell your personal information.</p><h3>4. Data Security</h3><p>We implement appropriate technical and organizational measures to protect your personal information against unauthorized access or disclosure.</p><h3>5. Your Rights</h3><p>You have the right to access, correct, or delete your personal information. Contact privacy@courtzon.com to exercise these rights.</p><h3>6. Cookies</h3><p>We use cookies to improve your experience and analyze usage. You can control cookie settings through your browser.</p><h3>7. Contact</h3><p>For privacy inquiries: privacy@courtzon.com.</p>\"}',NULL,1,1,'2026-05-21 11:47:45','2026-05-21 11:47:45'),(46,23,'hero','term_hero','Terms of Service',NULL,'{\"heading\":\"Terms of Service\",\"subheading\":\"Last updated: January 2026\"}',NULL,0,1,'2026-05-21 11:47:45','2026-05-21 11:47:45'),(47,23,'text','term_text',NULL,NULL,'{\"html\":\"<h3>1. Acceptance of Terms</h3><p>By using CourtZon, you agree to these Terms of Service. If you do not agree, please do not use our platform.</p><h3>2. Account Registration</h3><p>You must provide accurate information when creating an account. You are responsible for all activities under your account.</p><h3>3. Booking and Payments</h3><p>All bookings are subject to availability and facility cancellation policies. Payments are processed securely through our partners.</p><h3>4. User Conduct</h3><p>You agree not to misuse our platform, violate laws, harass other users, or submit false information.</p><h3>5. Facility Partners</h3><p>Facility partners are independent entities. CourtZon is not responsible for facility quality or disputes.</p><h3>6. Intellectual Property</h3><p>All content and trademarks on CourtZon are owned by or licensed to us. Do not copy or modify without permission.</p><h3>7. Limitation of Liability</h3><p>CourtZon is provided as is. We are not liable for indirect or consequential damages.</p><h3>8. Changes</h3><p>We may update these terms. Continued use constitutes acceptance.</p><h3>9. Contact</h3><p>For questions: legal@courtzon.com.</p>\"}',NULL,1,1,'2026-05-21 11:47:45','2026-05-21 11:47:45'),(48,24,'hero','sell_hero','Sell With CourtZon','Join our marketplace and reach thousands of sports enthusiasts','{\"heading\":\"Sell With Us\",\"subheading\":\"List your products on CourtZon Marketplace and reach thousands of active sports players looking for equipment and gear.\"}',NULL,0,1,'2026-05-21 11:47:45','2026-05-21 11:47:45'),(49,24,'features','sell_feat','Why Sell on CourtZon?',NULL,'{\"columns\":3,\"features\":[{\"icon\":\"chart\",\"title\":\"Reach Active Buyers\",\"description\":\"Access thousands of sports players actively looking for equipment, gear, and accessories.\"},{\"icon\":\"shield\",\"title\":\"Secure Payments\",\"description\":\"All transactions processed through our secure payment gateway with seller protection.\"},{\"icon\":\"bolt\",\"title\":\"Easy Setup\",\"description\":\"Create your seller profile in minutes. List products, manage inventory, and track orders from one dashboard.\"},{\"icon\":\"star\",\"title\":\"Low Commission\",\"description\":\"Competitive commission rates so you keep more. Transparent fee structure with no hidden costs.\"},{\"icon\":\"community\",\"title\":\"Seller Community\",\"description\":\"Join a growing community of sports equipment sellers. Share tips and grow together.\"},{\"icon\":\"chart\",\"title\":\"Analytics Dashboard\",\"description\":\"Track your sales, revenue, and product performance with detailed reports.\"}]}',NULL,1,1,'2026-05-21 11:47:45','2026-05-21 11:47:45'),(50,24,'cta','sell_cta','Ready to start selling?','Join hundreds of sellers already growing th